class Solution:
    def findIntegers(self, num: int) -> int:
        bits = bin(num)[2:]
        from functools import lru_cache
        @lru_cache(None)
        def dp(i, prev1, tight):
            if i == len(bits):
                return 1
            limit = int(bits[i]) if tight else 1
            ans = 0
            for d in range(0, limit+1):
                if prev1 and d == 1:
                    continue
                ans += dp(i+1, d==1, tight and d==limit)
            return ans
        return dp(0, False, True)

